      "path": "src/modules/tasks/routes.js",
      "content": "const express = require('express');
const tasksService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.get('/', async (req, res) => {
  const projectId = req.params.projectId;
  try {
    const tasks = await tasksService.getTasksByProject(projectId);
    res.json({ tasks });
  } catch (error) {
    if (error.code === 'PROJECT_NOT_FOUND') {
      sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
    } else {
      sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
    }
  }
});

router.get('/?status=done', async (req, res) => {
  const projectId = req.params.projectId;
  try {
    const tasks = await tasksService.getDoneTasksByProject(projectId);
    res.json({ tasks });
  } catch (error) {
    if (error.code === 'PROJECT_NOT_FOUND') {
      sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
    } else {
      sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
    }
  }
});

router.patch('/:taskId', async (req, res) => {
  const projectId = req.params.projectId;
  const taskId = req.params.taskId;
  const { status } = req.body;
  if (!['todo', 'done'].includes(status)) {
    return sendError(res, 400, 'INVALID_STATUS', 'Invalid task status');
  }
  try {
    const updatedTask = await tasksService.updateTaskStatus(projectId, taskId, status);
    res.json({ task: updatedTask });
  } catch (error) {
    if (error.code === 'PROJECT_NOT_FOUND') {
      sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
    } else if (error.code === 'TASK_NOT_FOUND') {
      sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
    } else {
      sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
    }
  }
});

module.exports = router;
