      "path": "src/modules/tasks/service.js",
      "content": "const { generateId } = require('../../lib/id');
const projectsService = require('../projects/service');

let tasksStore = [];

async function getTasksByProject(projectId) {
  const projectExists = await projectsService.getAllProjects().then(projects => projects.some(project => project.id === projectId));
  if (!projectExists) {
    throw { code: 'PROJECT_NOT_FOUND' };
  }
  return tasksStore.filter(task => task.projectId === projectId);
}

async function getDoneTasksByProject(projectId) {
  const projectExists = await projectsService.getAllProjects().then(projects => projects.some(project => project.id === projectId));
  if (!projectExists) {
    throw { code: 'PROJECT_NOT_FOUND' };
  }
  return tasksStore.filter(task => task.projectId === projectId && task.status === 'done');
}

async function updateTaskStatus(projectId, taskId, status) {
  const projectExists = await projectsService.getAllProjects().then(projects => projects.some(project => project.id === projectId));
  if (!projectExists) {
    throw { code: 'PROJECT_NOT_FOUND' };
  }
  const taskIndex = tasksStore.findIndex(task => task.projectId === projectId && task.id === taskId);
  if (taskIndex === -1) {
    throw { code: 'TASK_NOT_FOUND' };
  }
  tasksStore[taskIndex].status = status;
  return tasksStore[taskIndex];
}

module.exports = { getTasksByProject, getDoneTasksByProject, updateTaskStatus };
